      abstract class CrossoverOperator {
        {abstract} # generateChild()
        {abstract} # isCompatible()
        {abstract} # isSymmetric()
      }

      class CompositionCrossover {
        + generateChild()
        + isCompatible()
        + isSymmetric()
      }

      class MaximalPreservationCrossover {
        - rand : Random
        + generateChild()
        + isCompatible()
        + isSymmetric()
        + setSeed()
      }

      class OnePointCrossover {
        - RNG : Random
        + generateChild()
        + isCompatible()
        + isSymmetric()
        + setRandomSeed()
      }

      class UniformCrossover {
        - RNG : Random
        + generateChild()
        + isCompatible()
        + isSymmetric()
        + setRandomSeed()
      }

      class TwoPointCrossover {
        - RNG : Random
        + generateChild()
        + isCompatible()
        + isSymmetric()
        + setRandomSeed()
      }

      class OrdinalNumberMean {
        + OrdinalNumberMean()
        + generateChild()
        + isCompatible()
        + isSymmetric()
      }

      CrossoverOperationType o-- CrossoverOperator : crossoverOperator

      CrossoverOperator <|-- CompositionCrossover
      CrossoverOperator <|-- MaximalPreservationCrossover
      CrossoverOperator <|-- OnePointCrossover
      CrossoverOperator <|-- UniformCrossover
      CrossoverOperator <|-- TwoPointCrossover
      CrossoverOperator <|-- OrdinalNumberMean

    }
  }
}
